const LOGO_B64 = "";

// ── DATA ─────────────────────────────────────────────────────────────────────
const CLASSES = {
  1: { name: "Classe 1 — B1" },
  2: { name: "Classe 2 — B2" },
  3: { name: "Classe 3 — B3" },
};

const STUDENTS = {
  1: [
    { id: 10, firstname: "Alice",    lastname: "MARTIN"  },
    { id: 11, firstname: "Benoît",   lastname: "DUPONT"  },
    { id: 12, firstname: "Clara",    lastname: "LEFEVRE" },
  ],
  2: [
    { id: 20, firstname: "Sabrina",  lastname: "DILYA"     },
    { id: 21, firstname: "François", lastname: "LEROUX"    },
    { id: 22, firstname: "José",     lastname: "GARCIA"    },
    { id: 23, firstname: "Sarah",    lastname: "ISQUIERDA" },
    { id: 24, firstname: "Mina",     lastname: "DERECHA"   },
  ],
  3: [
    { id: 30, firstname: "Omar",     lastname: "BENTALI" },
    { id: 31, firstname: "Léa",      lastname: "VASSEUR" },
  ]
};

const SEMESTERS = {
  1: {
    label: "1er Semestre",
    subjects: [
      { id: "s1_devops",  name: "DevOps & Infra",        teacher: "M. MARTIN"   },
      { id: "s1_crypto",  name: "Cryptographie",          teacher: "Mme. DUBOIS" },
      { id: "s1_reverse", name: "Reverse Engineering",    teacher: "M. LEFEBVRE" },
      { id: "s1_pentest", name: "Pentest",                teacher: "Mme. EGARDE" },
    ]
  },
  2: {
    label: "2ème Semestre",
    subjects: [
      { id: "s2_reseau",  name: "Sécurité Réseau",        teacher: "M. BERNARD"  },
      { id: "s2_cloud",   name: "Cloud & Infrastructure",  teacher: "Mme. MOREL"  },
      { id: "s2_forensic",name: "Forensic",                teacher: "M. SIMON"    },
      { id: "s2_osint",   name: "OSINT & Veille",          teacher: "Mme. PETIT"  },
    ]
  }
};

// Grades: studentId → semesterId → subjectId → [{label, note, coeff}]
const GRADES = {};

// Appreciations: studentId → semesterId → { subjects: {subjectId: text}, global: text }
const APPRE = {};

// Helper: init student data
function ensureStudent(sid, sem) {
  if (!GRADES[sid]) GRADES[sid] = {};
  if (!GRADES[sid][sem]) {
    GRADES[sid][sem] = {};
    SEMESTERS[sem].subjects.forEach(sub => {
      GRADES[sid][sem][sub.id] = getDefaultGrades(sid, sem, sub.id);
    });
  }
  if (!APPRE[sid]) APPRE[sid] = {};
  if (!APPRE[sid][sem]) {
    APPRE[sid][sem] = { subjects: {}, global: "" };
  }
}

function getDefaultGrades(sid, sem, subId) {
  // Some pre-filled grades matching the existing mock data
  const presets = {
    10: { 1: {
      s1_devops:  [{label:"Programmation",note:15.25,coeff:0.5},{label:"Audit",note:16,coeff:1},{label:"Site web",note:18,coeff:1},{label:"Oral",note:9,coeff:3},{label:"Python",note:14.5,coeff:1},{label:"Ansible",note:2.10,coeff:3},{label:"Chiffrement",note:20,coeff:4}],
      s1_crypto:  [{label:"TP Chiffrement symétrique",note:17,coeff:2},{label:"TP Chiffrement asymétrique",note:15,coeff:2},{label:"Examen final",note:16,coeff:3},{label:"Projet PKI",note:16,coeff:3}],
      s1_reverse: [{label:"TP Assembleur",note:12,coeff:2},{label:"Crackme niveau 1",note:14,coeff:1},{label:"Crackme niveau 2",note:6,coeff:2},{label:"Examen",note:9,coeff:3}],
      s1_pentest: [{label:"Reconnaissance",note:12,coeff:1},{label:"Exploitation",note:6,coeff:3},{label:"Rapport",note:10,coeff:2},{label:"Présentation",note:7,coeff:2}],
    }},
    11: { 1: {
      s1_devops:  [{label:"Programmation",note:15.25,coeff:0.5},{label:"Audit",note:16,coeff:1},{label:"Site web",note:18,coeff:1},{label:"Oral",note:9,coeff:3},{label:"Python",note:14.5,coeff:1},{label:"Ansible",note:2.10,coeff:3},{label:"Chiffrement",note:20,coeff:4}],
      s1_crypto:  [{label:"TP Chiffrement symétrique",note:17,coeff:2},{label:"TP Chiffrement asymétrique",note:15,coeff:2},{label:"Examen final",note:16,coeff:3},{label:"Projet PKI",note:16,coeff:3}],
      s1_reverse: [{label:"TP Assembleur",note:12,coeff:2},{label:"Crackme niveau 1",note:14,coeff:1},{label:"Crackme niveau 2",note:6,coeff:2},{label:"Examen",note:9,coeff:3}],
      s1_pentest: [{label:"Reconnaissance",note:12,coeff:1},{label:"Exploitation",note:6,coeff:3},{label:"Rapport",note:10,coeff:2},{label:"Présentation",note:7,coeff:2}],
    }},
  };
  if (presets[sid] && presets[sid][sem] && presets[sid][sem][subId]) {
    return JSON.parse(JSON.stringify(presets[sid][sem][subId]));
  }
  // Default empty grade set
  return [
    { label: "Contrôle continu", note: 10, coeff: 1 },
    { label: "Examen final",     note: 10, coeff: 2 },
  ];
}

// ── STATE ─────────────────────────────────────────────────────────────────────
let state = { classId: null, studentId: null, semester: 1, dirty: false };

// ── INIT ──────────────────────────────────────────────────────────────────────
document.getElementById("classSelect").addEventListener("change", e => {
  const cid = parseInt(e.target.value);
  state.classId = cid || null;
  state.studentId = null;
  populateStudents(cid);
  renderPage();
});

document.getElementById("studentSelect").addEventListener("change", e => {
  const sid = parseInt(e.target.value);
  state.studentId = sid || null;
  renderPage();
});

document.querySelectorAll(".sem-btn").forEach(btn => {
  btn.addEventListener("click", () => {
    document.querySelectorAll(".sem-btn").forEach(b => b.classList.remove("active"));
    btn.classList.add("active");
    state.semester = parseInt(btn.dataset.sem);
    renderPage();
  });
});

document.getElementById("pdfBtn").addEventListener("click", generatePDF);

function populateStudents(classId) {
  const sel = document.getElementById("studentSelect");
  sel.innerHTML = "<option value=''>— Choisir —</option>";
  sel.disabled = !classId;
  if (!classId) return;
  (STUDENTS[classId] || []).forEach(s => {
    const o = document.createElement("option");
    o.value = s.id;
    o.textContent = s.lastname + " " + s.firstname;
    sel.appendChild(o);
  });
}

// ── RENDER ────────────────────────────────────────────────────────────────────
function renderPage() {
  const hasStudent = state.classId && state.studentId;
  document.getElementById("emptyMain").style.display = hasStudent ? "none" : "flex";
  document.getElementById("contentGrid").style.display = hasStudent ? "grid" : "none";
  document.getElementById("pdfBtn").disabled = !hasStudent;
  document.getElementById("mentionBanner").style.display = hasStudent ? "flex" : "none";

  if (!hasStudent) return;

  ensureStudent(state.studentId, state.semester);
  renderSubjects();
  renderAppreciations();
  updateGlobalAvg();
}

function renderSubjects() {
  const container = document.getElementById("subjectsContainer");
  container.innerHTML = "";
  const sem = SEMESTERS[state.semester];
  const grades = GRADES[state.studentId][state.semester];

  sem.subjects.forEach(sub => {
    const g = grades[sub.id];
    const avg = computeAvg(g);
    const avgStr = avg !== null ? avg.toFixed(2) : "—";
    const avgClass = avg === null ? "" : avg >= 12 ? "good" : avg >= 8 ? "warn" : "bad";

    const card = document.createElement("div");
    card.className = "subject-card";
    card.innerHTML = `
      <div class="sc-header">
        <div class="sc-info">
          <span class="sc-name">${sub.name}</span>
          <span class="sc-teacher">${sub.teacher}</span>
        </div>
        <div class="sc-avg-wrap">
          <span class="sc-avg ${avgClass}">${avgStr}</span>
          <span class="sc-avg-label">/20</span>
        </div>
      </div>
      <table class="grade-table">
        <thead>
          <tr><th>Épreuve</th><th>Note /20</th><th>Coeff</th><th></th></tr>
        </thead>
        <tbody id="tbody_${sub.id}">
          ${g.map((row, i) => gradeRowHTML(sub.id, i, row)).join("")}
        </tbody>
      </table>
      <div class="sc-actions">
        <button class="btn-add-row" onclick="addRow('${sub.id}')">＋ Ajouter une épreuve</button>
      </div>
    `;
    container.appendChild(card);
  });
}

function gradeRowHTML(subId, idx, row) {
  const nc = noteClass(row.note);
  return `
    <tr data-sub="${subId}" data-idx="${idx}">
      <td><input class="grade-input label-in" type="text" value="${escHtml(row.label)}" onchange="updateGrade('${subId}',${idx},'label',this.value)"></td>
      <td><input class="grade-input note-in ${nc}" type="number" min="0" max="20" step="0.5" value="${row.note}" onchange="updateGrade('${subId}',${idx},'note',parseFloat(this.value))"></td>
      <td><input class="grade-input coeff-in" type="number" min="0.5" max="10" step="0.5" value="${row.coeff}" onchange="updateGrade('${subId}',${idx},'coeff',parseFloat(this.value))"></td>
      <td><button class="btn-del-row" onclick="deleteRow('${subId}',${idx})" title="Supprimer">✕</button></td>
    </tr>`;
}

function renderAppreciations() {
  const appreList = document.getElementById("appreList");
  appreList.innerHTML = "";
  const sem = SEMESTERS[state.semester];
  const appData = APPRE[state.studentId][state.semester];

  sem.subjects.forEach(sub => {
    const val = appData.subjects[sub.id] || "";
    const div = document.createElement("div");
    div.className = "appre-item";
    div.innerHTML = `
      <label class="appre-label">${sub.name}</label>
      <textarea class="appre-textarea" placeholder="Appréciation pour ${sub.name}…" 
        onchange="updateAppre('${sub.id}', this.value)">${escHtml(val)}</textarea>
    `;
    appreList.appendChild(div);
  });

  document.getElementById("globalAppre").value = appData.global || "";
  document.getElementById("globalAppre").onchange = function() {
    APPRE[state.studentId][state.semester].global = this.value;
  };
}

// ── GRADE OPS ─────────────────────────────────────────────────────────────────
function updateGrade(subId, idx, field, val) {
  GRADES[state.studentId][state.semester][subId][idx][field] = val;
  refreshSubjectAvg(subId);
  updateGlobalAvg();
}

function addRow(subId) {
  GRADES[state.studentId][state.semester][subId].push({ label: "Nouvelle épreuve", note: 10, coeff: 1 });
  renderSubjects();
  renderAppreciations();
  updateGlobalAvg();
}

function deleteRow(subId, idx) {
  GRADES[state.studentId][state.semester][subId].splice(idx, 1);
  renderSubjects();
  renderAppreciations();
  updateGlobalAvg();
}

function updateAppre(subId, val) {
  APPRE[state.studentId][state.semester].subjects[subId] = val;
}

function refreshSubjectAvg(subId) {
  const g = GRADES[state.studentId][state.semester][subId];
  const avg = computeAvg(g);
  const avgStr = avg !== null ? avg.toFixed(2) : "—";
  const card = document.querySelector(`#tbody_${subId}`)?.closest(".subject-card");
  if (card) {
    const avgEl = card.querySelector(".sc-avg");
    avgEl.textContent = avgStr;
    avgEl.className = "sc-avg " + (avg === null ? "" : avg >= 12 ? "good" : avg >= 8 ? "warn" : "bad");
  }
}

function updateGlobalAvg() {
  const sid = state.studentId;
  const sem = state.semester;
  if (!sid || !GRADES[sid] || !GRADES[sid][sem]) return;

  const subjects = SEMESTERS[sem].subjects;
  let totalW = 0, totalN = 0;
  subjects.forEach(sub => {
    const g = GRADES[sid][sem][sub.id];
    const a = computeAvg(g);
    if (a !== null) { totalN += a; totalW++; }
  });

  const globalAvg = totalW > 0 ? (totalN / totalW) : null;
  const avgStr = globalAvg !== null ? globalAvg.toFixed(2) : "—";
  document.getElementById("globalAvg").textContent = avgStr + " /20";

  const mention = globalAvg !== null
    ? (globalAvg >= 10 ? "ADMIS(E)" : "RECALÉ(E)")
    : "—";
  const mentionEl = document.getElementById("mentionText");
  mentionEl.textContent = mention;
  mentionEl.className = "mention-value " + (globalAvg !== null ? (globalAvg >= 10 ? "admis" : "recale") : "");
}

// ── HELPERS ───────────────────────────────────────────────────────────────────
function computeAvg(grades) {
  if (!grades || grades.length === 0) return null;
  const tc = grades.reduce((s, g) => s + (g.coeff || 0), 0);
  if (tc === 0) return null;
  return grades.reduce((s, g) => s + (g.note || 0) * (g.coeff || 0), 0) / tc;
}

function noteClass(n) {
  if (n >= 16) return "perfect";
  if (n >= 12) return "good";
  if (n >= 8)  return "warn";
  return "bad";
}

function escHtml(s) {
  return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
}

function showToast(msg, type = "") {
  const t = document.getElementById("toast");
  t.textContent = msg;
  t.className = "toast " + type;
  void t.offsetWidth;
  t.classList.add("show");
  setTimeout(() => t.classList.remove("show"), 3000);
}

// ── PDF GENERATION ────────────────────────────────────────────────────────────
function generatePDF() {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ unit: "mm", format: "a4", orientation: "portrait" });

  const sid = state.studentId;
  const sem = state.semester;
  const semInfo = SEMESTERS[sem];
  const classId = state.classId;

  // Find student
  let student = null;
  (STUDENTS[classId] || []).forEach(s => { if (s.id === sid) student = s; });
  if (!student) return;

  const studentName = student.lastname + " " + student.firstname;
  const className = CLASSES[classId].name;
  const appData = APPRE[sid] && APPRE[sid][sem] ? APPRE[sid][sem] : { subjects: {}, global: "" };

  // Compute per-subject averages
  const subjects = semInfo.subjects;
  let totalN = 0, totalW = 0;
  const subjectAvgs = subjects.map(sub => {
    const g = GRADES[sid][sem][sub.id];
    const avg = computeAvg(g);
    if (avg !== null) { totalN += avg; totalW++; }
    return { ...sub, avg };
  });
  const globalAvg = totalW > 0 ? (totalN / totalW) : null;
  const mention = globalAvg !== null ? (globalAvg >= 10 ? "ADMIS(E)" : "RECALÉ(E)") : "—";

  // ─── Colors ───
  const C_BLUE    = [0, 123, 255];
  const C_DARK    = [30, 41, 59];
  const C_MUTED   = [100, 116, 139];
  const C_BG      = [248, 249, 250];
  const C_BORDER  = [222, 226, 230];
  const C_GREEN   = [16, 185, 129];
  const C_RED     = [239, 68, 68];
  const C_YELLOW  = [245, 158, 11];

  const W = 210, H = 297;
  const ML = 14, MR = 14;
  const CW = W - ML - MR; // content width

  // ─── Header border ───
  doc.setFillColor(...C_BLUE);
  doc.rect(0, 0, W, 3, "F");

  // ─── Logo ───
  doc.addImage("data:image/jpeg;base64," + LOGO_B64, "JPEG", ML, 8, 18, 18);

  // ─── School info ───
  doc.setFont("helvetica", "bold");
  doc.setFontSize(16);
  doc.setTextColor(...C_BLUE);
  doc.text("GuardiNet", ML + 22, 16);
  doc.setFont("helvetica", "normal");
  doc.setFontSize(8.5);
  doc.setTextColor(...C_MUTED);
  doc.text("Campus de Cybersécurité", ML + 22, 21);
  doc.text("12 Rue du Code, 75000 Paris", ML + 22, 25.5);

  // ─── Student info (top right) ───
  doc.setFont("helvetica", "bold");
  doc.setFontSize(13);
  doc.setTextColor(...C_DARK);
  doc.text(studentName, W - MR, 14, { align: "right" });
  doc.setFont("helvetica", "normal");
  doc.setFontSize(8.5);
  doc.setTextColor(...C_MUTED);
  doc.text("Classe : " + className, W - MR, 20, { align: "right" });
  doc.text("N° Étudiant : " + (20250000 + sid), W - MR, 25, { align: "right" });

  // ─── Divider ───
  doc.setDrawColor(...C_BORDER);
  doc.setLineWidth(0.5);
  doc.line(ML, 31, W - MR, 31);

  // ─── Bulletin title ───
  doc.setFont("helvetica", "bold");
  doc.setFontSize(13);
  doc.setTextColor(70, 70, 70);
  const titleY = 39;
  doc.text("BULLETIN DE NOTES — " + semInfo.label.toUpperCase(), W / 2, titleY, { align: "center" });

  // ─── Grades table ───
  const tableData = subjectAvgs.map(sub => {
    const avgStr = sub.avg !== null ? sub.avg.toFixed(2) : "—";
    const appre = appData.subjects[sub.id] || "—";
    return [sub.name + "\n" + sub.teacher, avgStr, "12.00", appre];
  });

  doc.autoTable({
    startY: titleY + 5,
    head: [["Matière & Professeur", "Moy. Élève (/20)", "Moy. Classe (/20)", "Appréciations générales"]],
    body: tableData,
    margin: { left: ML, right: MR },
    tableWidth: CW,
    styles: {
      font: "helvetica",
      fontSize: 9,
      cellPadding: { top: 5, right: 4, bottom: 5, left: 4 },
      lineColor: C_BORDER,
      lineWidth: 0.3,
      textColor: C_DARK,
      valign: "middle",
    },
    headStyles: {
      fillColor: [241, 243, 245],
      textColor: [51, 51, 51],
      fontStyle: "bold",
      fontSize: 8,
      halign: "center",
    },
    columnStyles: {
      0: { cellWidth: 48, fontStyle: "bold" },
      1: { cellWidth: 26, halign: "center", fontStyle: "bold" },
      2: { cellWidth: 26, halign: "center" },
      3: { cellWidth: CW - 48 - 26 - 26, fontStyle: "italic", textColor: C_MUTED, fontSize: 8.5 },
    },
    didParseCell: function(data) {
      if (data.column.index === 1 && data.section === "body") {
        const val = parseFloat(data.cell.raw);
        if (!isNaN(val)) {
          if (val < 10) { data.cell.styles.textColor = [220, 38, 38]; data.cell.styles.fontStyle = "bold"; }
          else { data.cell.styles.textColor = [5, 150, 105]; }
        }
      }
    },
    alternateRowStyles: { fillColor: [253, 254, 255] },
  });

  const afterTable = doc.lastAutoTable.finalY + 8;

  // ─── Footer box ───
  const footerH = 40;
  const footerY = afterTable;
  doc.setFillColor(...C_BG);
  doc.setDrawColor(...C_BORDER);
  doc.setLineWidth(0.4);
  doc.roundedRect(ML, footerY, CW, footerH, 3, 3, "FD");

  // ─── Global comments ───
  const globalText = appData.global || "Aucun avis saisi.";
  doc.setFont("helvetica", "bold");
  doc.setFontSize(9.5);
  doc.setTextColor(...C_BLUE);
  doc.text("Avis du conseil de classe :", ML + 5, footerY + 9);
  doc.setFont("helvetica", "normal");
  doc.setFontSize(8.5);
  doc.setTextColor(68, 68, 68);
  const lines = doc.splitTextToSize(globalText, CW - 70);
  doc.text(lines, ML + 5, footerY + 15);

  // ─── Average box (right side of footer) ───
  const boxW = 48, boxH = 30;
  const boxX = W - MR - boxW;
  const boxY = footerY + 5;
  doc.setFillColor(255, 255, 255);
  doc.setDrawColor(...C_BLUE);
  doc.setLineWidth(1.5);
  doc.roundedRect(boxX, boxY, boxW, boxH, 3, 3, "FD");

  doc.setFont("helvetica", "normal");
  doc.setFontSize(7);
  doc.setTextColor(...C_MUTED);
  doc.text("MOYENNE GÉNÉRALE", boxX + boxW / 2, boxY + 7, { align: "center" });

  const avgDisplay = globalAvg !== null ? globalAvg.toFixed(2) : "—";
  doc.setFont("helvetica", "bold");
  doc.setFontSize(22);
  doc.setTextColor(...C_BLUE);
  doc.text(avgDisplay, boxX + boxW / 2, boxY + 21, { align: "center" });

  // ─── Mention ───
  const mentionY = afterTable + footerH + 8;
  const mentionColor = globalAvg !== null ? (globalAvg >= 10 ? C_GREEN : C_RED) : C_MUTED;
  const mentionBg = globalAvg !== null ? (globalAvg >= 10 ? [209, 250, 229] : [254, 226, 226]) : [241, 245, 249];

  doc.setFillColor(...mentionBg);
  doc.setDrawColor(...mentionColor);
  doc.setLineWidth(1);
  doc.roundedRect(ML, mentionY, CW, 14, 3, 3, "FD");

  doc.setFont("helvetica", "bold");
  doc.setFontSize(11);
  doc.setTextColor(...mentionColor);
  doc.text("Décision du conseil de classe : " + mention, W / 2, mentionY + 9, { align: "center" });

  // ─── Signature ───
  const sigY = mentionY + 24;
  doc.setFont("helvetica", "normal");
  doc.setFontSize(9);
  doc.setTextColor(...C_MUTED);
  doc.text("Le Directeur Pédagogique,", W - MR, sigY, { align: "right" });
  doc.setFont("times", "bolditalic");
  doc.setFontSize(16);
  doc.setTextColor(...C_DARK);
  doc.text("A. Dupont", W - MR, sigY + 12, { align: "right" });

  // ─── Page footer ───
  doc.setFont("helvetica", "normal");
  doc.setFontSize(7);
  doc.setTextColor(180, 180, 180);
  const today = new Date().toLocaleDateString("fr-FR", { day: "2-digit", month: "long", year: "numeric" });
  doc.text("GuardiNet — Campus de Cybersécurité · Document généré le " + today, W / 2, H - 8, { align: "center" });
  doc.setDrawColor(220, 220, 220);
  doc.line(ML, H - 11, W - MR, H - 11);

  const filename = `Bulletin_${student.lastname}_${semInfo.label.replace(" ", "_")}.pdf`;
  doc.save(filename);
  showToast("Bulletin PDF généré avec succès !", "success");
}